"use strict";parserFactory.register("readnoveldaily.com",()=>new ReadnoveldailyParser),parserFactory.register("allnovelbook.com",()=>new ReadnoveldailyParser);class ReadnoveldailyParser extends Parser{constructor(){super()}async getChapterUrls(e,t){return this.getChapterUrlsFromMultipleTocPages(e,this.extractPartialChapterList,this.getUrlsOfTocPages,t)}getUrlsOfTocPages(e){let t=[],r=[...e.querySelectorAll("ul.pagination li a:not([rel])")];if(0<r.length){let e=new URL(r.pop().href),n=e.searchParams.get("page");for(let r=2;r<=n;++r)e.searchParams.set("page",r),t.push(e.href)}return t}extractPartialChapterList(e){return[...e.querySelectorAll("#viewchapter .row a")].map(e=>util.hyperLinkToChapter(e))}findContent(e){return e.querySelector("#content")}isHTMLUnknownElement(e){return e instanceof HTMLUnknownElement}removeUnknownElement(e){for(let t of e.childNodes)this.isHTMLUnknownElement(t)?t.remove():this.removeUnknownElement(t)}removeUnwantedElementsFromContentElement(e){util.removeElements(e.querySelectorAll("div.box-ads")),this.removeUnknownElement(e),super.removeUnwantedElementsFromContentElement(e)}extractSubject(e){return[...e.querySelectorAll("div.fiction-info span.tags .label")].map(e=>e.textContent.trim()).join(", ")}extractTitleImpl(e){return e.querySelector(".detail-post h2")}extractAuthor(e){return e.querySelector(".author a")?.textContent??super.extractAuthor(e)}findChapterTitle(e){return e.querySelector(".chapter-title")}findCoverImageUrl(e){return util.getFirstImgSrc(e,".book")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll(".m-desc .inner")]}}